// packages/database/src/db/schema/subscription.ts
// Drizzle table: subscription (generated by scripts/split-schema.ts)

import { pgTable, uniqueIndex, text, boolean, timestamp, type AnyPgColumn } from './_shared'
import { createId } from '@paralleldrive/cuid2'

import { ShopifyIntegration } from './shopify-integration'
import { Organization } from './organization'

/** Drizzle table for subscription */
export const Subscription = pgTable(
  'Subscription',
  {
    id: text()
      .$defaultFn(() => createId())
      .primaryKey()
      .notNull(),
    createdAt: timestamp({ precision: 3 }).defaultNow().notNull(),
    updatedAt: timestamp({ precision: 3 }).notNull(),
    provider: text().notNull(),
    providerId: text().notNull(),
    topic: text().notNull(),
    format: text().notNull(),
    secret: text(),
    active: boolean().default(true).notNull(),
    organizationId: text()
      .notNull()
      .references((): AnyPgColumn => Organization.id, { onUpdate: 'cascade', onDelete: 'cascade' }),
    integrationId: text()
      .notNull()
      .references((): AnyPgColumn => ShopifyIntegration.id, {
        onUpdate: 'cascade',
        onDelete: 'cascade',
      }),
  },
  (table) => [
    uniqueIndex('Subscription_provider_integrationId_topic_key').using(
      'btree',
      table.provider.asc().nullsLast(),
      table.integrationId.asc().nullsLast(),
      table.topic.asc().nullsLast()
    ),
  ]
)
